blocks.body:
{
    "level": "B2–C1",
    "intro": "W tym temacie poznasz <strong>bezosobową stronę bierną</strong>, konstrukcję służącą do przekazywania informacji, gdy źródło jest <strong>nieznane</strong>, <strong>nieistotne</strong> lub gdy chcesz nadać tekstowi <strong>bardziej formalny</strong>.",
    "rules": [
        {
            "label": "Budowa 1",
            "color": "emerald",
            "text": "<strong>To + jest/było + V3 + tamto + klauzula</strong>:",
            "example": "It is said that he is very rich."
        },
        {
            "label": "Budowa 2",
            "color": "blue",
            "text": "<strong>Podmiot + jest/był + V3 + do + bezokolicznik</strong>:",
            "example": "He is said to be very rich."
        },
        {
            "label": "Czasowniki",
            "color": "rose",
            "text": "Czasowniki raportujące: <strong>powiedz, wierz, myśl, wiem, zgłaszaj, oczekuj, rozważ</strong>",
            "example": "She is believed to be the best candidate."
        }
    ]
}

{
    "title": "1. Czasowniki sprawozdawcze w stronie biernej bezosobowej",
    "intro": "Czasowniki użyte w stronie biernej bezosobowej:",
    "items": [
        {
            "label": "mowić",
            "title": "Mówi się, że... / Mówi się, że podmiot...",
            "subtitle": "Mówią, że..."
        },
        {
            "label": "uważać",
            "title": "Uważa się, że... / Uważa się, że podmiot...",
            "subtitle": "Uważa się, że..."
        },
        {
            "label": "myśleć",
            "title": "Uważa się, że... / Uważa się, że podmiot...",
            "subtitle": "Wierzą, że..."
        },
        {
            "label": "wiedzieć",
            "title": "Wiadomo, że... / Wiadomo, że podmiot...",
            "subtitle": "Wiadomo, że..."
        },
        {
            "label": "raport",
            "title": "Doniesiono, że... / Podmiot zostaje zgłoszony...",
            "subtitle": "Poinformowano, że..."
        },
        {
            "label": "oczekiwać",
            "title": "Oczekuje się, że... /Oczekuje się, że podmiot...",
            "subtitle": "Oczekuje się, że..."
        },
        {
            "label": "rozważać",
            "title": "Uważa się, że... / Podmiot jest uważany za...",
            "subtitle": "Uważa się, że..."
        },
        {
            "label": "przypuszczać",
            "title": "Przypuszcza się, że... / Podmiot ma...",
            "subtitle": "Zakłada się, że..."
        }
    ]
}

{
    "title": "2. Konstrukcja: To + jest/było + V3 + tamto...",
    "sections": [
        {
            "label": "Obecny",
            "color": "emerald",
            "description": "<strong>To + V3 + to...</strong> — o teraźniejszości:",
            "examples": [
                {
                    "en": "It is said that he works very hard.",
                    "ua": "Mówią, że bardzo ciężko pracuje."
                },
                {
                    "en": "It is believed that the company is growing.",
                    "ua": "Firma uważana jest za rozwijającą się."
                },
                {
                    "en": "It is reported that the situation is improving.",
                    "ua": "Z doniesień wynika, że ​​sytuacja się poprawia."
                }
            ]
        },
        {
            "label": "Przeszłość",
            "color": "blue",
            "description": "<strong>To było + V3 + to...</strong> — o przeszłości:",
            "examples": [
                {
                    "en": "It was thought that the project would fail.",
                    "ua": "Wierzono, że projekt zakończy się fiaskiem."
                },
                {
                    "en": "It was reported that the accident happened at night.",
                    "ua": "Ze zgłoszenia wynikało, że do wypadku doszło w nocy."
                },
                {
                    "en": "It was believed that he was innocent.",
                    "ua": "Uznano go za niewinnego."
                }
            ]
        },
        {
            "label": "Inne czasy",
            "color": "amber",
            "description": "Inne czasy: <strong>Powiedziano, zostanie podane...</strong>:",
            "examples": [
                {
                    "en": "It has been reported that the storm is approaching.",
                    "ua": "Zgłoszono, że zbliża się burza."
                },
                {
                    "en": "It will be announced that the winner is...",
                    "ua": "Zwycięzca zostanie ogłoszony..."
                }
            ]
        }
    ]
}

{
    "title": "3. Konstrukcja: Podmiot + jest/był + V3 + do + bezokolicznik",
    "sections": [
        {
            "label": "do + Bezokolicznik prosty",
            "color": "emerald",
            "description": "<strong>być / robić</strong> to czynność występująca jednocześnie z czasownikiem raportującym:",
            "examples": [
                {
                    "en": "He is said to be a good doctor.",
                    "ua": "Mówią, że to dobry lekarz."
                },
                {
                    "en": "She is believed to know the truth.",
                    "ua": "Uważa się, że zna prawdę."
                },
                {
                    "en": "They are reported to be in Paris.",
                    "ua": "Według doniesień są w Paryżu."
                }
            ]
        },
        {
            "label": "do + Doskonały Bezokolicznik",
            "color": "blue",
            "description": "<strong>zrobić</strong> — czynność poprzedza czasownik raportujący:",
            "examples": [
                {
                    "en": "He is said to have won the lottery.",
                    "ua": "Mówią, że wygrał na loterii."
                },
                {
                    "en": "She is believed to have left the country.",
                    "ua": "Uważa się, że opuściła kraj."
                },
                {
                    "en": "They are reported to have stolen millions.",
                    "ua": "Według doniesień ukradli miliony."
                }
            ]
        },
        {
            "label": "do + Ciągły Bezokolicznik",
            "color": "amber",
            "description": "<strong>do zrobienia</strong> — działanie w procesie:",
            "examples": [
                {
                    "en": "He is said to be working on a new project.",
                    "ua": "Mówią, że pracuje nad nowym projektem."
                },
                {
                    "en": "She is believed to be living in London.",
                    "ua": "Uważa się, że mieszka w Londynie."
                },
                {
                    "en": "They are reported to be hiding somewhere.",
                    "ua": "Z doniesień wynika, że ​​gdzieś się ukrywają."
                }
            ]
        }
    ]
}

{
    "title": "4. Transformacja Aktywna → Bezosobowa Pasywna",
    "intro": "Jak zamienić zdanie czynne w bezosobową stronę bierną:",
    "rows": [
        {
            "en": "Active: People say that he is rich.",
            "ua": "Ludzie mówią, że jest bogaty.",
            "note": "→ It is said that he is rich. / He is said to be rich."
        },
        {
            "en": "Active: They believe that she knows the truth.",
            "ua": "Wierzą, że zna prawdę.",
            "note": "→ It is believed that... / She is believed to know..."
        },
        {
            "en": "Active: Reports say that the company is growing.",
            "ua": "Z raportów wynika, że ​​firma się rozwija.",
            "note": "→ It is reported that... / The company is reported to be growing."
        },
        {
            "en": "Active: They thought that he had left.",
            "ua": "Myśleli, że już go nie ma.",
            "note": "→ It was thought that... / He was thought to have left."
        }
    ],
    "warning": "📌 Użyj bezokolicznika doskonałego (aby zrobić), jeśli czynność miała miejsce wcześniej!"
}

{
    "title": "5. Kiedy używać strony biernej bezosobowej?",
    "sections": [
        {
            "label": "Nieznane źródło",
            "color": "emerald",
            "description": "Gdy <strong>źródło informacji jest nieznane</strong> lub nieprecyzyjne:",
            "examples": [
                {
                    "en": "It is said that the castle is haunted.",
                    "ua": "Mówi się, że zamek jest nawiedzony."
                },
                {
                    "en": "It is believed that the earth is 4.5 billion years old.",
                    "ua": "Uważa się, że Ziemia ma 4,5 miliarda lat."
                }
            ]
        },
        {
            "label": "Styl formalny",
            "color": "blue",
            "description": "W <strong>wiadomościach, dokumentach oficjalnych, tekstach akademickich</strong>:",
            "examples": [
                {
                    "en": "The suspect is reported to have fled the country.",
                    "ua": "Z nieoficjalnych informacji wynika, że ​​podejrzany uciekł za granicę."
                },
                {
                    "en": "The economy is expected to grow by 3%.",
                    "ua": "Oczekuje się, że gospodarka wzrośnie o 3%."
                }
            ]
        },
        {
            "label": "Obiektywność",
            "color": "amber",
            "description": "W przypadku <strong>obiektywnej prezentacji</strong> bez osobistej opinii:",
            "examples": [
                {
                    "en": "It is thought that the painting is a forgery.",
                    "ua": "Uważa się, że zdjęcie jest fałszywe."
                },
                {
                    "en": "He is considered to be an expert in the field.",
                    "ua": "Uważany jest za eksperta w tej dziedzinie."
                }
            ]
        },
        {
            "label": "Plotki, przypuszczenia",
            "color": "rose",
            "description": "W przypadku <strong>plotek, niepotwierdzonych danych</strong>:",
            "examples": [
                {
                    "en": "The celebrity is rumored to be dating a famous actor.",
                    "ua": "Krążą plotki, że celebrytka spotyka się ze znanym aktorem."
                },
                {
                    "en": "It is alleged that the politician took bribes.",
                    "ua": "Zarzuca się, że polityk brał łapówki."
                }
            ]
        }
    ]
}

{
    "title": "6. Inne czasowniki w stronie biernej bezosobowej",
    "intro": "Rozszerzona lista czasowników:",
    "items": [
        {
            "label": "twierdzić",
            "title": "Zarzuca się, że...",
            "subtitle": "Twierdzi się (bez dowodów), że..."
        },
        {
            "label": "prawo",
            "title": "Twierdzi się, że...",
            "subtitle": "Twierdzi się, że..."
        },
        {
            "label": "plotka",
            "title": "Krążą pogłoski, że...",
            "subtitle": "Krążą pogłoski, że..."
        },
        {
            "label": "oszacować",
            "title": "Szacuje się, że...",
            "subtitle": "Według szacunków..."
        },
        {
            "label": "przypuszczać",
            "title": "Zakłada się, że...",
            "subtitle": "Zakłada się, że..."
        },
        {
            "label": "zrozumieć",
            "title": "Rozumie się, że...",
            "subtitle": "Istnieje zrozumienie, że..."
        }
    ]
}

{
    "title": "7. Typowe błędy",
    "items": [
        {
            "label": "Błąd 1",
            "color": "rose",
            "title": "Brak to przed bezokolicznikiem.",
            "wrong": "He is said be rich.",
            "right": "✅ He is said to be rich."
        },
        {
            "label": "Błąd 2",
            "color": "amber",
            "title": "Zły wybór między infinitive simple i perfect.",
            "wrong": "He is said to leave yesterday. (czynność wcześniejsza)",
            "right": "✅ He is said to have left yesterday."
        },
        {
            "label": "Błąd 3",
            "color": "sky",
            "title": "Mieszanie dwóch konstrukcji.",
            "wrong": "He is said that to be rich.",
            "right": "✅ He is said to be rich."
        },
        {
            "label": "Błąd 4",
            "color": "rose",
            "title": "Niedopasowanie czasu w zdaniu reported.",
            "wrong": "It is said that he was working there. (jeśli nadal tam pracuje)",
            "right": "✅ It is said that he works there."
        }
    ]
}
